/* Paritran site interactivity. Vanilla, no framework, no external requests.
 * Every animation is gated by prefers-reduced-motion. Data is fetched from
 * same-origin JSON generated by scripts/site/export_replay.py (real seed-42). */
(function () {
  "use strict";
  var REDUCE = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  var COLORS = ["#2E7273", "#A87229", "#2D6A4F", "#1E3A6B", "#7A2E2E", "#9fb0cf"];

  function $(s, r) { return (r || document).querySelector(s); }
  function $all(s, r) { return Array.prototype.slice.call((r || document).querySelectorAll(s)); }

  /* ---- scroll counters ---------------------------------------------------- */
  function animateCount(el) {
    var target = parseFloat(el.getAttribute("data-count"));
    var dp = parseInt(el.getAttribute("data-dp") || "0", 10);
    if (REDUCE) { el.textContent = target.toFixed(dp); return; }
    var start = null, dur = 900;
    function step(ts) {
      if (start === null) start = ts;
      var p = Math.min(1, (ts - start) / dur);
      var eased = 1 - Math.pow(1 - p, 3);
      el.textContent = (target * eased).toFixed(dp);
      if (p < 1) requestAnimationFrame(step); else el.textContent = target.toFixed(dp);
    }
    requestAnimationFrame(step);
  }
  var countObs = new IntersectionObserver(function (entries) {
    entries.forEach(function (e) {
      if (e.isIntersecting) { animateCount(e.target); countObs.unobserve(e.target); }
    });
  }, { threshold: 0.4 });
  $all("[data-count]").forEach(function (el) { countObs.observe(el); });

  /* ---- pipeline tap toggle (hover handled by CSS) ------------------------- */
  $all("#pipe .step").forEach(function (s) {
    s.addEventListener("click", function () { s.classList.toggle("open"); });
  });

  /* ---- nav active highlight ---------------------------------------------- */
  var navLinks = {};
  $all(".navlinks a").forEach(function (a) { navLinks[a.getAttribute("href").slice(1)] = a; });
  var navObs = new IntersectionObserver(function (entries) {
    entries.forEach(function (e) {
      var link = navLinks[e.target.id];
      if (link && e.isIntersecting) {
        $all(".navlinks a").forEach(function (x) { x.classList.remove("active"); });
        link.classList.add("active");
      }
    });
  }, { rootMargin: "-40% 0px -55% 0px" });
  Object.keys(navLinks).forEach(function (id) { var s = document.getElementById(id); if (s) navObs.observe(s); });

  /* ---- video chapter chips ------------------------------------------------ */
  var video = $(".demo-video");
  $all("#beatChips .chip").forEach(function (c) {
    c.addEventListener("click", function () {
      if (!video) return;
      video.currentTime = parseFloat(c.getAttribute("data-t")) || 0;
      var p = video.play(); if (p && p.catch) p.catch(function () {});
    });
  });
  if (video) {
    video.addEventListener("timeupdate", function () {
      var t = video.currentTime, chips = $all("#beatChips .chip"), active = null;
      chips.forEach(function (c) { if (parseFloat(c.getAttribute("data-t")) <= t) active = c; });
      chips.forEach(function (c) { c.classList.toggle("active", c === active); });
    });
  }

  /* ---- V3 collapse canvas ------------------------------------------------- */
  (function collapse() {
    var canvas = $("#collapseCanvas"); if (!canvas || !canvas.getContext) return;
    var ctx = canvas.getContext("2d");
    var dpr = Math.min(2, window.devicePixelRatio || 1);
    var data = null, raf = null;
    fetch("assets/data/graph_replay.json").then(function (r) { return r.json(); }).then(function (d) {
      data = d;
      canvas.width = d.meta.w * dpr; canvas.height = d.meta.h * dpr;
      canvas.style.aspectRatio = d.meta.w + "/" + d.meta.h;
      ctx.scale(dpr, dpr);
      var io = new IntersectionObserver(function (es) {
        es.forEach(function (e) { if (e.isIntersecting) { play(); io.unobserve(canvas); } });
      }, { threshold: 0.25 });
      io.observe(canvas);
    }).catch(function () {});

    function draw(prog) {
      var m = data.meta; ctx.clearRect(0, 0, m.w, m.h);
      var idx = {}; data.nodes.forEach(function (n) { idx[n.id] = n; });
      // edges (only when both endpoints mostly landed)
      ctx.lineWidth = 0.5;
      data.edges.forEach(function (e) {
        var a = idx[e[0]], b = idx[e[1]]; if (!a || !b) return;
        var ra = a.revealAt / data.nodes.length, rb = b.revealAt / data.nodes.length;
        if (prog < Math.max(ra, rb) + 0.15) return;
        ctx.strokeStyle = "rgba(159,176,228,0.18)";
        ctx.beginPath(); ctx.moveTo(pos(a, prog).x, pos(a, prog).y); ctx.lineTo(pos(b, prog).x, pos(b, prog).y); ctx.stroke();
      });
      data.nodes.forEach(function (n) {
        var rv = n.revealAt / data.nodes.length; if (prog < rv) return;
        var p = pos(n, prog);
        ctx.fillStyle = n.net >= 0 ? COLORS[n.net] : "rgba(159,176,228,0.5)";
        ctx.beginPath(); ctx.arc(p.x, p.y, n.net >= 0 ? 3.2 : 2, 0, 6.2832); ctx.fill();
      });
    }
    function pos(n, prog) {
      var rv = n.revealAt / data.nodes.length;
      var t = Math.max(0, Math.min(1, (prog - rv) / (1 - rv + 0.0001)));
      var e = 1 - Math.pow(1 - t, 3);
      return { x: n.x0 + (n.x1 - n.x0) * e, y: n.y0 + (n.y1 - n.y0) * e };
    }
    function play() {
      if (!data) return;
      if (REDUCE) { draw(1); return; }
      var start = null, dur = 2600;
      cancelAnimationFrame(raf);
      function step(ts) { if (start === null) start = ts; var p = Math.min(1, (ts - start) / dur); draw(p); if (p < 1) raf = requestAnimationFrame(step); }
      raf = requestAnimationFrame(step);
    }
    var btn = $("#replayCollapse"); if (btn) btn.addEventListener("click", play);
  })();

  /* ---- V4 money trail svg ------------------------------------------------- */
  (function trail() {
    var svg = $("#trailSvg"); if (!svg) return;
    fetch("assets/data/money_trail.json").then(function (r) { return r.json(); }).then(function (d) {
      var n = d.network, NS = "http://www.w3.org/2000/svg";
      function add(tag, attrs, txt) {
        var el = document.createElementNS(NS, tag);
        Object.keys(attrs).forEach(function (k) { el.setAttribute(k, attrs[k]); });
        if (txt != null) el.textContent = txt; svg.appendChild(el); return el;
      }
      function rupees(v) { return "Rs " + (v / 100000).toFixed(1) + "L"; }
      add("text", { x: 6, y: 16, fill: "#6B685E", "font-family": "var(--font-mono)", "font-size": 11 },
        n.victims.count + " victims traced through network " + n.id);
      // columns: victims, L1, L2, cash
      var cols = [
        { x: 20, label: "victims", sub: rupees(n.victims.total) },
        { x: 150, label: n.l1_count + " L1 mules", sub: "" },
        { x: 270, label: "L2 account", sub: "" },
        { x: 370, label: "cash-out", sub: "" }
      ];
      cols.forEach(function (c) {
        add("rect", { x: c.x, y: 90, width: 46, height: 46, rx: 6, fill: "#1E3A6B" });
        add("text", { x: c.x + 23, y: 152, "text-anchor": "middle", fill: "#14213d", "font-family": "var(--font-sans)", "font-size": 11 }, c.label);
        if (c.sub) add("text", { x: c.x + 23, y: 166, "text-anchor": "middle", fill: "#6B685E", "font-family": "var(--font-mono)", "font-size": 10 }, c.sub);
      });
      function hop(x1, x2, broken, amount) {
        add("line", { x1: x1, y1: 113, x2: x2, y2: 113, stroke: broken ? "#7A2E2E" : "#2D6A4F", "stroke-width": broken ? 3 : 2, "stroke-dasharray": broken ? "5 4" : "0" });
        add("text", { x: (x1 + x2) / 2, y: 106, "text-anchor": "middle", fill: broken ? "#7A2E2E" : "#2D6A4F", "font-family": "var(--font-mono)", "font-size": 9 }, amount);
      }
      hop(66, 150, false, rupees(n.victims.total));
      hop(196, 270, n.hops.some(function (h) { return h.to.indexOf("L2") >= 0 && h.broken; }), "");
      hop(316, 370, n.hops[n.hops.length - 1].broken, "");
      add("text", { x: 6, y: 230, fill: "#2D6A4F", "font-family": "var(--font-mono)", "font-size": 11 },
        "this network: " + n.traced_pct_this_network + "% traced to cash-out");
    }).catch(function () {});
  })();

  /* ---- V8 gate widget ----------------------------------------------------- */
  (function gate() {
    var input = $("#gateInput"), verdict = $("#gateVerdict"), exc = $("#gateExcerpt");
    if (!input) return;
    var excerpt = "";
    function norm(s) { return s.replace(/\s+/g, " ").trim().toLowerCase(); }
    function check() {
      var ok = excerpt && norm(excerpt).indexOf(norm(input.value)) >= 0 && input.value.trim().length > 0;
      verdict.textContent = ok ? "PASSED: found verbatim in the statute." : "WITHHELD: not a verbatim quote of the statute.";
      verdict.className = "verdict " + (ok ? "pass" : "fail");
    }
    fetch("assets/data/statute_excerpts.json").then(function (r) { return r.json(); }).then(function (d) {
      excerpt = d.excerpt; if (exc) exc.textContent = d.excerpt;
      input.value = d.prefilled_quote; check();
    }).catch(function () {});
    input.addEventListener("input", check);
    $("#gateBreak").addEventListener("click", function () {
      var words = input.value.split(" ");
      for (var i = 0; i < words.length; i++) { if (words[i].length > 4) { words[i] = "tampered"; break; } }
      input.value = words.join(" "); check(); input.focus();
    });
    $("#gateReset").addEventListener("click", function () {
      fetch("assets/data/statute_excerpts.json").then(function (r) { return r.json(); }).then(function (d) { input.value = d.prefilled_quote; check(); });
    });
  })();

  /* ---- V9 tamper-the-chain widget ---------------------------------------- */
  (function chain() {
    var wrap = $("#chain"); if (!wrap || !window.crypto || !crypto.subtle) return;
    var texts = [
      "intake: complaint NCRP-0001 hashed",
      "entity: phone +91xxxxxx91 linked",
      "linkage: complaint joined to network 3",
      "money: hop MULE_L1 to MULE_L2 recorded",
      "packet: Section 63 draft assembled",
      "officer: link accepted by supervisor1"
    ];
    var original = texts.slice();
    function hex(buf) { return Array.prototype.map.call(new Uint8Array(buf), function (b) { return ("0" + b.toString(16)).slice(-2); }).join(""); }
    function sha(str) { return crypto.subtle.digest("SHA-256", new TextEncoder().encode(str)).then(hex); }
    function build() {
      var prev = "0".repeat(64), stored = [];
      var chainP = Promise.resolve();
      texts.forEach(function (t) {
        chainP = chainP.then(function () { return sha(prev + t); }).then(function (h) { stored.push({ prev: prev, hash: h }); prev = h; });
      });
      return chainP.then(function () { return stored; });
    }
    function render(stored, brokenFrom) {
      wrap.innerHTML = "";
      texts.forEach(function (t, i) {
        var broken = brokenFrom >= 0 && i >= brokenFrom;
        var row = document.createElement("div"); row.className = "link" + (broken ? " broken" : "");
        row.innerHTML = '<div class="idx">' + (i + 1) + '</div><div class="box"><div class="rec" data-i="' + i + '">' + t + '</div><div class="hash">' + stored[i].hash.slice(0, 24) + '..</div></div>';
        wrap.appendChild(row);
      });
    }
    function verifyAndRender() {
      build().then(function (fresh) {
        // recompute against current texts; find first index where a re-hash diverges from a clean rebuild
        // (since we rebuild from current texts, a tampered record propagates from its index)
        var brokenFrom = -1;
        for (var i = 0; i < texts.length; i++) { if (texts[i] !== original[i]) { brokenFrom = i; break; } }
        render(fresh, brokenFrom);
        var status = $("#chainStatus");
        status.textContent = brokenFrom >= 0 ? ("Chain breaks at record " + (brokenFrom + 1) + ". Every fingerprint from there on stops matching.") : "Chain verified. Every record's fingerprint matches.";
        status.className = "verdict " + (brokenFrom >= 0 ? "fail" : "pass");
      });
    }
    verifyAndRender();
    $("#tamperBtn").addEventListener("click", function () {
      var rec = wrap.querySelector('.rec[data-i="2"]'); if (!rec) return;
      rec.setAttribute("contenteditable", "true"); rec.focus();
      rec.addEventListener("input", function () { texts[2] = rec.textContent; verifyAndRender(); reFocus(); });
      function reFocus() { var r = wrap.querySelector('.rec[data-i="2"]'); if (r) { r.setAttribute("contenteditable", "true"); } }
    });
    $("#restoreBtn").addEventListener("click", function () { texts = original.slice(); verifyAndRender(); });
  })();

  /* ---- S12 feature grid (all 36, from audit/features.json) ---------------- */
  var FEATURES = [
    ["Nine-stage deterministic pipeline", "One button runs all nine steps from intake to officer sign-off, timing each.", "REAL"],
    ["Mule-network discovery", "Links complaints sharing phones, devices or accounts; finds 6 networks in 297 complaints (F1 0.962).", "REAL"],
    ["Live force-graph collapse", "Complaint dots stream in over SSE and clump into colored networks.", "REAL"],
    ["Money trail by reachability", "Follows stolen money hop by hop; 90.8% of value traced to cash-out.", "REAL"],
    ["Animated money-trail diagram", "Victim to L1 to L2 to cash-out with amounts; broken hops are freeze points.", "REAL"],
    ["Recoverability triage", "Ranks networks by freezable money using a four-term formula. Accounts, never people.", "REAL"],
    ["Three-path legal mapping", "BM25, InLegalBERT and rules; only agreement is HIGH confidence (100%, 8/8 and 15/15).", "REAL"],
    ["Verbatim bare-act corpus", "Official India Code text committed with checksums; a test proves every quote is real.", "REAL"],
    ["F9 groundedness gate", "Every citation checked word for word; invented or paraphrased ones withheld, 0 leaked.", "REAL"],
    ["Plant-a-fabrication control", "Injects a fake citation through the real gate; the gate blocks it live.", "REAL"],
    ["Live local LLM generation", "gemma3:4b drafts citations on the local machine; 5 passed, 1 withheld, 0 leaked.", "REAL"],
    ["Labelled deterministic stub", "Fabricates on purpose so the gate is demonstrable off the model (50/40/10/0).", "STUB"],
    ["Section 63 packet assembly", "Court packet: hashes, network, money trail, verbatim quotes, F9 audit, chain head.", "REAL"],
    ["BSA 63(4) certificate", "Pre-fills the two-part certificate; signature blocks stay blank; print to PDF.", "REAL"],
    ["DB-enforced audit ledger", "A Postgres trigger assigns seq, timestamp and SHA-256 hashes; updates and deletes rejected.", "REAL"],
    ["Auditor tamper test", "Corrupts a scratch copy; verification breaks at that record; the real chain is untouched.", "REAL"],
    ["Custody Ledger screen", "Hash-chained list with drawn connectors and an honest threat-model line.", "REAL"],
    ["Officer decisions on record", "Reject a link or claim; the decision appends to the tamper-evident chain.", "REAL"],
    ["Seed-42 Reproduce diff", "Reruns the engine and diffs every number against results.json, all rows green.", "REAL"],
    ["Judge's seed control", "Any seed reruns the full engine; every number moves consistently.", "REAL"],
    ["Evaluation harness", "Every run logs git SHA, corpus versions, generator, sample sizes; shows the lift rows.", "REAL"],
    ["Rule-augmented NER", "Pulls phones, UPI, accounts, IFSC, IPs; precision 0.74, recall 1.0 on planted identifiers.", "REAL"],
    ["Hindi/Gujarati text handling", "IndicNLP script normalization before extraction across English, Hindi, Gujarati.", "REAL"],
    ["PDF/scan OCR ingest", "Reads a text layer, falls back to Tesseract for scans, hashes the file on intake.", "REAL"],
    ["Synthetic case generator", "Builds 297 complaints across 6 planted syndicates with zero real PII.", "REAL"],
    ["Role-based auth", "Officer, supervisor, auditor with Argon2id and per-role rate limits.", "REAL"],
    ["Security posture panel", "Live output of six scanners plus an OWASP Top 10:2025 checklist.", "REAL"],
    ["Zero egress measured", "Lists the one outbound endpoint and runs a live TCP self-test, blocked Wi-Fi off.", "REAL"],
    ["Guided demo mode", "One button paces a five-beat story over the real engine in a measured 34.2 s.", "REAL"],
    ["System Status widget", "Live db, Ollama and model health plus a p50/p95 latency sparkline.", "REAL"],
    ["Prometheus + Grafana", "An 8-panel dashboard; the audit chain head is exported as a metric.", "INFRA"],
    ["Command palette", "Keyboard palette jumps to any screen or starts a run without the mouse.", "REAL"],
    ["On-premise docker stack", "Five services from one command in 13 s; only three ports face the host.", "INFRA"],
    ["Standalone prototype slice", "One 240-line Python file reproduces every measured metric.", "REAL"],
    ["191-test suite", "In-container pytest, vitest and Playwright with a reproduction gate and a truth grep.", "INFRA"],
    ["Honest degradation", "If a model is down the run completes with an explicit degraded flag, never silent.", "REAL"]
  ];
  (function featGrid() {
    var grid = $("#featGrid"); if (!grid) return;
    FEATURES.forEach(function (f) {
      var card = document.createElement("div"); card.className = "fcard"; card.setAttribute("data-status", f[2]);
      var lab = f[2] === "REAL" ? "real" : f[2] === "STUB" ? "stub" : "infra";
      card.innerHTML = '<h4>' + f[0] + '</h4><p>' + f[1] + '</p><span class="lab ' + lab + '">' + f[2] + '</span>';
      grid.appendChild(card);
    });
    function counts() {
      var vis = { all: FEATURES.length, REAL: 0, STUB: 0, INFRA: 0 };
      FEATURES.forEach(function (f) { vis[f[2]]++; });
      $("#cAll").textContent = "(" + vis.all + ")"; $("#cREAL").textContent = "(" + vis.REAL + ")";
      $("#cSTUB").textContent = "(" + vis.STUB + ")"; $("#cINFRA").textContent = "(" + vis.INFRA + ")";
    }
    counts();
    $all("#featFilters .fbtn").forEach(function (b) {
      b.addEventListener("click", function () {
        $all("#featFilters .fbtn").forEach(function (x) { x.classList.remove("active"); });
        b.classList.add("active");
        var f = b.getAttribute("data-f");
        $all(".fcard", grid).forEach(function (c) { c.hidden = !(f === "all" || c.getAttribute("data-status") === f); });
      });
    });
  })();
})();
